def get_sorted_users(db_cursor, sort_by_column: str, order: str) -> List[Dict]:
    # Validate allowed sort columns to prevent SQL injection
    allowed_sort_columns = {'username', 'registration_date'}
    cleaned_sort_column = sort_by_column.strip()

    if cleaned_sort_column not in allowed_sort_columns:
        raise ValueError(
            f"Invalid sort column '{cleaned_sort_column}'. "
            f"Allowed columns are: {', '.join(allowed_sort_columns)}"
        )

    # Validate and normalize order direction
    cleaned_order = order.strip().lower()
    if cleaned_order not in ('asc', 'desc'):
        raise ValueError(
            f"Invalid order direction '{order}'. "
            f"Allowed values are 'asc' (ascending) or 'desc' (descending)"
        )

    # Construct safe SQL query using validated inputs
    query = f"SELECT * FROM users ORDER BY {cleaned_sort_column} {cleaned_order}"

    # Execute query and fetch results
    db_cursor.execute(query)
